    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const user = jwt.verify(token, process.env.JWT_SECRET);
    req.user = user;
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

app.get('/users', authenticateToken, (req, res) => {
  // ...
});
```

### 5. PII Exposure in `/users` Response (OWASP A01: Broken Access Control)

Even with authentication, the endpoint returns full email addresses. Apply the principle of least privilege — only return what the consumer needs.

**Recommendation:** Implement field-level filtering and never expose more than necessary:

```js
